@Slf4j
@Lazy
@Service
@RequiredArgsConstructor(onConstructor_ = {@Autowired})
public class StandaardRekenUitAgendaService implements RekenUitAgendaService {

    private final OpdrachtService opdrachtService;
    private final RekenAgendaService rekenagendaService;
    private final RekenmotorService rekenmotorService;
    private final RekenmotorService vormArtikelsRekenmotorService;
    private final RekenMotorStrategyFactory rekenMotorStrategyFactory;
    private final LockLogService lockLogService;
    private final RekenenHelpService rekenenHelpService;
    private final RekenResultatenService rekenResultatenService;
    private final MaandTotaalService maandTotaalService;
    private final CoreHrConfigurationService coreHrConfigurationService;

    private static final int REKENEN_ITEMNR = 9;


    private static final List<LockLogDTO> LOCKS = ImmutableList.of(new LockLogDTO(LockItemId.ALLPID, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLREKENAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLWACHTAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLMT, REKENEN_ITEMNR, LockType.EXCLUSIVE));

    @Override
    public MetaRekenFeedback start(Admin admin, String actor, RekenContext actionParams) {
        Werkgever werkgever = actionParams.getUnchecked(RekenActionParamKey.WERKGEVER_KEY);
        Rekenmodus modus = actionParams.getUnchecked(RekenActionParamKey.REKENMODUS_KEY);
        if (werkgever != null && modus != null) {
            return doeBerekeningenUitRekenAgenda(werkgever, modus, actor);
        } else {
            throw new MessageException("RekenUitAgendaService.run onvoldoende parameters");
        }
    }

    @Override
    public MetaRekenFeedback doeBerekeningenUitRekenAgenda(Werkgever werkgever, Rekenmodus modus, String actor) {
        MetaRekenFeedback metaFeedback = new MetaRekenFeedback(RekenActionType.REKEN_UIT_REKENAGENDA, modus);
        List<LockLog> lockedItems = new ArrayList<>();
        try {
            Admin admin = werkgever.getAdmin();
            lockedItems = lockLogService.lockItems(admin, LOCKS, actor);
            CacheContext.getInstance().clearCachedServices(Scope.ALL);
            log.trace("doeBerekeningenUitRekenAgenda(werkgeverid:{} ({});", werkgever.getId(), admin.getAdminDirTrimmed());

            TemporalContext.getInstance().setActualInterval(new Eternity());
            List<RekenAgenda> rekenagendas;
            try {
                CriteriaBuilder cb = new CriteriaBuilder();
                cb.fetch("persoon{persoonSlices,opdrachten{opdrachtSlices}},werkgever{admin, werkgeverSlices}");
                cb.and("werkgever", Criterium.EQ(werkgever));
                rekenagendas = rekenagendaService.findByCriteria(admin, cb);
            } finally {
                TemporalContext.getInstance().clearActualInterval();
            }
            RekenmotorDtoConverter converter = new RekenmotorDtoConverter(Arrays.asList(werkgever));
            checkInterupted();
            SetMultimap<RekenAtoom, Integer> rekenAtomenMap = bepaalRekenAtomen(admin, rekenagendas);
            List<RekenagendaDTO> rekenagendaDTOS = converter.convertRekenagendas(rekenagendas);
            metaFeedback.zetRekenAgendaEnRekenAtomen(rekenAtomenMap, rekenagendaDTOS);
            schatAantalMaandOpdrachten(rekenAtomenMap.keySet());
            doeBerekeningenUitRekenAgendaPuntNoCacheClear(admin, rekenAtomenMap, modus, actor, metaFeedback);
            rekenagendaService.deleteAll(admin, werkgever);
            rekenagendas.stream()
                    .map(RekenAgenda::getPersoon)
                    .filter(Objects::nonNull)
                    .map(Identifiable::getId)
                    .distinct()
                    .forEach(persoonId -> rekenenHelpService.verwijderRegulsZonderOverlappendeOpdracht(admin, persoonId));
        } finally {
            LockLogHelper lockLogHelper = new LockLogHelper(lockLogService, log);
            lockLogHelper.unlockItems(werkgever.getAdmin(), lockedItems);
        }
        return metaFeedback;
    }

    @Override
    public SetMultimap<RekenAtoom, Integer> bepaalRekenAtomen(Admin admin, List<RekenAgenda> rekenAgendas) {
        LocalDateTime rekenTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();
        for (RekenAgenda punt : rekenAgendas) {
            atomenMap.putAll(bepaalRekenAtomen(admin, punt, rekenTijdstip));
        }
        return atomenMap;
    }

    private SetMultimap<RekenAtoom, Integer> bepaalRekenAtomen(Admin admin, RekenAgenda punt, LocalDateTime rekenTijdstip) {
        log.trace("bepaalRekenAtomen({});", LogTools.toSimpleLog(punt));
        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();
        List<Opdracht> opdrachten = findOpdrachtenByRekenagenda(admin, punt);
        LocalDate beginDatum = punt.getBeginDatum().dayOfMonth().withMinimumValue();
        LocalDate eindDatum = punt.getEindDatum().dayOfMonth().withMaximumValue();
        LocalDate loopDatum = beginDatum;
        LocalDate rekenDatum = punt.getRekenDatum();
        LocalDate boekDatum = punt.getBoekDatum();
        while (loopDatum.compareTo(eindDatum) <= 0) {
            for (Opdracht opdracht : opdrachten) {
                LocalDateInterval rekenPeriode = new Month(loopDatum);
                LocalDate beslagDatum = punt.getBeslagDatum();
                if (beslagDatum.isBefore(rekenPeriode.getStart())) {
                    beslagDatum = rekenPeriode.getStart();
                }
                RekenTijd rekenTijd = new RekenTijd(rekenPeriode, rekenDatum, boekDatum, beslagDatum, rekenTijdstip);
                RekenAtoom atoom = new RekenAtoom(rekenTijd, opdracht.getPersoon().getId());
                atomenMap.put(atoom, opdracht.getOpdrachtnr());
            }
            loopDatum = loopDatum.plusMonths(1);
        }
        return atomenMap;
    }

    private void schatAantalMaandOpdrachten(Set<RekenAtoom> rekenAtomen) {
        if (!rekenAtomen.isEmpty()) {
            RekenProcesImp.setTotaalStatic(rekenAtomen.size());
        } else {
            log.trace("Lege berekening");
            RekenProcesImp.setTotaalStatic(1);
            RekenProcesImp.incrementVerwerktStatic();
        }
    }

    private void doeBerekeningenUitRekenAgendaPuntNoCacheClear(
            Admin admin, SetMultimap<RekenAtoom, Integer> rekenAtomenMap, Rekenmodus modus,
            String actor, MetaRekenFeedback metaFeedback) {
        RekenMotorStrategy strategy = bepaalStrategy(admin, modus);
        RekenLogStatus status = RekenLogStatus.SUCCES;
        RekenContext rekenContext = new RekenContext();
        CoreHrConfiguratie coreHrConfiguratie = coreHrConfigurationService.getCoreHrConfiguratie(admin);
        for (RekenAtoom atoom : rekenAtomenMap.keySet()) {
            Set<Integer> opdrachtNrs = rekenAtomenMap.get(atoom);
            checkInterupted();
            try {
                if (modus == Rekenmodus.VORM_ARTIKELS) {
                    rekenContext = vormArtikelsRekenmotorService
                            .berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), strategy, modus, actor, coreHrConfiguratie);
                } else if (modus == Rekenmodus.VERMIJDEN_FICHE_25) {
                    RekenTijd rekenTijd1 = atoom.getRekenTijd();
                    //Ondanks de name heeft onderstaande methode hier niets te maken met artikels
                    //TODO kd hernoemen
                    rekenContext = vormArtikelsRekenmotorService
                            .berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, rekenTijd1, strategy, modus, actor, coreHrConfiguratie);
                    lockNieuweRekenResultaten(admin, opdrachtNrs, atoom.getPersoonId(), rekenTijd1.beginDatum);

                    LocalDate rekenDatum2 = rekenTijd1.rekenDatum.minusYears(1).withMonthOfYear(12).withDayOfMonth(31);
                    RekenTijd rekenTijd2 = new RekenTijd(rekenTijd1.rekenPeriode, rekenDatum2, rekenDatum2, rekenDatum2, rekenTijd1.rekenTijdstip);
                    RekenMotorStrategy strategyNormaal = bepaalStrategy(admin, Rekenmodus.NORMAAL);
                    rekenContext =
                            rekenmotorService.berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, rekenTijd2, strategyNormaal, modus, actor, coreHrConfiguratie);
                    verwijderenLock(admin, opdrachtNrs, atoom.getPersoonId(), rekenTijd2.beginDatum);
                } else {
                    rekenContext =
                            rekenmotorService.berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), strategy, modus, actor, coreHrConfiguratie);
                }
            } catch (Exception exception) {
                rekenenHelpService.logFatalException(admin, atoom.getRekenTijd().beginDatum, atoom.getPersoonId(), opdrachtNrs, exception);
                status = RekenLogStatus.FATAL_ERROR;
            }


            RekenFeedback rekenFeedback = metaFeedback.rekenFeedbackPerAtoom(atoom, rekenContext.getUnchecked(RekenChainKey.REKEN_FEEDBACK_KEY));
            RekenProcesImp.incrementVerwerktStatic();
            try {
                rekenenHelpService.doeRekenLog(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), modus, status, rekenFeedback, actor);
            } catch (Exception exception) {
                log.debug("Logging failed", exception);
            }
        }
    }

    private RekenMotorStrategy bepaalStrategy(Admin admin, Rekenmodus modus) {
        RekenMotorStrategy strategy;
        switch (modus) {
            case NEUTRAAL_REKENEN:
                strategy = rekenMotorStrategyFactory.getNeutralisatieStrategy(admin, false);
                break;
            case SOCIAAL_REKENEN:
                strategy = rekenMotorStrategyFactory.getSociaalRekenenStrategy(admin);
                break;
            case BIJSTUREN_EUROCENT:
                strategy = rekenMotorStrategyFactory.getBijsturenEuroCentStrategy(admin);
                break;
            case VORM_ARTIKELS:
                strategy = rekenMotorStrategyFactory.getVormArtikelStrategy(admin);
                break;
            case VERMIJDEN_FICHE_25:
                strategy = rekenMotorStrategyFactory.getVermijdenFiche25Strategy(admin);
                break;
            case NETTO_FISCAAL_VORIG_JAAR:
                strategy = rekenMotorStrategyFactory.getBerekenVorigFiscaalJaarStrategy(admin);
                break;
            case NORMAAL:
            case VOORSCHOT:
            default:
                strategy = rekenMotorStrategyFactory.getMaandTotalenStrategy(admin);
                break;
        }
        return strategy;
    }

    @Override
    public List<Opdracht> findOpdrachtenByRekenagenda(Admin admin, RekenAgenda rekenagenda) {
        return findOpdrachtenByRekenAgenda(admin, rekenagenda, null);
    }

    @Override
    public List<Opdracht> findOpdrachtenByRekenAgenda(Admin admin, RekenAgenda rekenagenda, String fetchFields) {
        CriteriaBuilder cb = new CriteriaBuilder(fetchFields);
        RekenagendaType rekenagendaType = rekenagendaService.valideer(rekenagenda);
        cb.and("werkgever", Criterium.EQ(rekenagenda.getWerkgever()));
        switch (rekenagendaType) {
            case HOEDANIGHEIDWERKGEVER:
                cb.and("opdrachtSlices.hoedanigheidCode", Criterium.EQ(rekenagenda.getHoedanigheid().getCode()));
                break;
            case REKENGROEPWERKGEVER:
                cb.and("opperSlices.weddeBerekening.rekenGroep", Criterium.EQ(rekenagenda.getRekenGroep().getCode()));
                break;
            case PERSOONOPDRACHTNR:
                cb.and("persoon", Criterium.EQ(rekenagenda.getPersoon()));
                cb.and("opdrachtnr", Criterium.EQ(rekenagenda.getOpdrachtNummer()));
                break;
            case WERKGEVER:
                break;
            default:
                throw new MessageException("Ongeldige rekenagenda");
        }
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setActualInterval(new LocalDateInterval(rekenagenda.getBeginDatum(), rekenagenda.getEindDatum()));
        List<Opdracht> opdrachten = opdrachtService.findByCriteria(rekenagenda.getWerkgever().getAdmin(), cb);
        temporalContext.clearActualInterval();
        return opdrachten;
    }

    private void checkInterupted() {
        if (RekenProcesImp.isInStopState()) {
            throw new ProcesHaltedException("Shall halt");
        }
    }

    private static final Integer TEMP_SNUMMER_VERMIJDEN_FICHE_281_25 = -10;

    private void lockNieuweRekenResultaten(Admin admin, Set<Integer> opdrachtNrs, Integer persoonId, LocalDate beginDatum) {
        rekenResultatenService.lockMetSnummer(admin, persoonId, opdrachtNrs, beginDatum, TEMP_SNUMMER_VERMIJDEN_FICHE_281_25);
        maandTotaalService.lockMetSnummer(admin, persoonId, opdrachtNrs, beginDatum, TEMP_SNUMMER_VERMIJDEN_FICHE_281_25);
    }

    private void verwijderenLock(Admin admin, Set<Integer> opdrachtNrs, Integer persoonId, LocalDate beginDatum) {
        rekenResultatenService.verwijderVanSnummer(admin, persoonId, opdrachtNrs, beginDatum, TEMP_SNUMMER_VERMIJDEN_FICHE_281_25);
        maandTotaalService.verwijderVanSnummer(admin, persoonId, opdrachtNrs, beginDatum, TEMP_SNUMMER_VERMIJDEN_FICHE_281_25);
    }
}
